if (! function_exists('text_markov_chain')) {
    function text_markov_chain($training_text, $output_words = null, $prefix_words = null)
    {
        $words = preg_split('/\s+/', trim($training_text));
        if (count($words) < 3) {
            return json_encode(['error' => 'Training text must have at least 3 words']);
        }
        $order = isset($prefix_words) ? max(1, min(5, (int)$prefix_words)) : 2;
        $chain = [];
        for ($i = 0; $i < count($words) - $order; $i++) {
            $prefix = implode(' ', array_slice($words, $i, $order));
            $next = $words[$i + $order];
            if (!isset($chain[$prefix])) {
                $chain[$prefix] = [];
            }
            $chain[$prefix][] = $next;
        }
        if (empty($chain)) {
            return json_encode(['error' => 'Could not build chain from training text']);
        }
        // Start with a random prefix
        $prefixKeys = array_keys($chain);
        $currentPrefix = $prefixKeys[array_rand($prefixKeys)];
        $output = explode(' ', $currentPrefix);
        $targetWords = isset($output_words) ? max($order, (int)$output_words) : 20;
        $maxIterations = 1000;
        $iter = 0;
        while (count($output) < $targetWords && $iter < $maxIterations) {
            $iter++;
            if (isset($chain[$currentPrefix])) {
                $next = $chain[$currentPrefix][array_rand($chain[$currentPrefix])];
                $output[] = $next;
                $prefixParts = explode(' ', $currentPrefix);
                array_shift($prefixParts);
                $prefixParts[] = $next;
                $currentPrefix = implode(' ', $prefixParts);
            } else {
                // Dead end, pick new random prefix
                $currentPrefix = $prefixKeys[array_rand($prefixKeys)];
            }
        }
        return json_encode([
            'generated' => implode(' ', $output),
            'word_count' => count($output),
            'unique_prefixes' => count($chain),
            'order' => $order
        ]);
    }
